const payload = JSON.parse(JSON.stringify(items[0].json));
const config = payload.__config ?? {};
const publicationId = config.beehiivPublicationId || $env.BEEHIIV_PUBLICATION_ID || '';
const apiKey = $env.BEEHIIV_API_KEY || '';
if (!payload.beehiivPayload) {
  payload.beehiivPayload = {};
}

if (!payload.beehiivEnabled || !publicationId || !apiKey) {
  payload.beehiivResponse = {
    skipped: true,
    reason: 'Beehiiv credentials missing or disabled.',
  };
  return [{ json: payload }];
}

try {
  const response = await $httpRequest({
    method: 'POST',
    url: `https://api.beehiiv.com/v2/publications/${publicationId}/drafts`,
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
    },
    body: payload.beehiivPayload,
    json: true,
    timeout: 20000,
  });
  payload.beehiivResponse = { skipped: false, data: response };
  payload.beehiivDraftUrl = response?.data?.web_url ?? null;
} catch (error) {
  payload.beehiivResponse = {
    skipped: true,
    reason: error.message,
  };
}

return [{ json: payload }];
